#include <bits/stdc++.h>
using namespace std;
typedef long long ll;
const int N=2e5+5,mod=998244353;
int n,k,a[N],num[N];
ll fac[N+N],g[N+N];
bool b[N+N];
ll quick_mi(ll x,ll y){
    ll ans=1,base=x;
    while(y){
        if(y&1)
            ans*=base,ans%=mod;
        y>>=1,base*=base,base%=mod;
    }
    return ans;
}
ll C(int x,int y){
    return fac[x]*g[x-y]%mod*g[y]%mod;
}
int main(){
    scanf("%d%d",&n,&k);
    for(int i=1;i<=n;i++){
        scanf("%d",&a[i]);
        b[a[i]]=1;
    }
    fac[0]=g[0]=1;
    for(int i=1;i<=N*2;i++)
        fac[i]=i*fac[i-1]%mod,g[i]=quick_mi(fac[i],mod-2);
    for(int i=1,j=0;i<=k;i++){
        while(b[j])
            j++;
        num[i]=j,b[j]=1;
    }
    ll ans=1;
    for(int i=1;i<=k;i++)
        ans+=C(num[i]+k-i,k-i+1),ans%=mod;
    printf("%lld",ans);
    return 0;
}
